const APPS_SCRIPT_URL="https://script.google.com/a/macros/stekom.ac.id/s/AKfycbyeKMVOQw_P13lILQ_XZT_okKf0bYJ4NvzDXLw2SaHScKE3vDx5_y9tFO0idrTzdXU-6A/exec";async function checkAccess(e){if(!e)return!1;try{const t=new URLSearchParams({email:e.toLowerCase().trim(),ua:navigator.userAgent.slice(0,100),ref:location.hostname}),c=await fetch(APPS_SCRIPT_URL+"?"+t,{cache:"no-store"});if(!c.ok)return!1;return!0===(await c.json()).allowed}catch(e){return!1}}